from pydantic import BaseModel
import os

class Settings(BaseModel):
    anthropic_api_key: str
    default_model: str = "claude-sonnet-4-6"

def get_settings() -> Settings:
    return Settings(
        anthropic_api_key=os.environ["ANTHROPIC_API_KEY"],
        default_model=os.environ.get("CLAUDE_MODEL", "claude-sonnet-4-6"),
    )

from anthropic import AsyncAnthropic
from fastapi import Depends

def get_anthropic_client(
    settings: Settings = Depends(get_settings),
) -> AsyncAnthropic:
    return AsyncAnthropic(api_key=settings.anthropic_api_key)

class ClaudeService:
    def __init__(self, client: AsyncAnthropic, settings: Settings):
        self.client = client
        self.settings = settings

    async def create_message(self, body):
        return await self.client.messages.create(
            model=body.model or self.settings.default_model,
            max_tokens=body.max_tokens,
            system=body.system,
            messages=[m.model_dump() for m in body.messages],
        )

def get_claude_service(
    client: AsyncAnthropic = Depends(get_anthropic_client),
    settings: Settings = Depends(get_settings),
) -> ClaudeService:
    return ClaudeService(client=client, settings=settings)

from fastapi import Request

def get_anthropic_client(request: Request) -> AsyncAnthropic:
    return request.app.state.anthropic_client

def get_claude_service(
    request: Request,
    settings: Settings = Depends(get_settings),
) -> ClaudeService:
    client: AsyncAnthropic = request.app.state.anthropic_client
    return ClaudeService(client=client, settings=settings)

